export const iconIndex: IconIndex = {
    allIcons,
    totalCount: 984,
}

// Optimized helper functions that derive data from allIcons
export const searchIcons = (query: string): IconMetadata[] => {
    const lowercaseQuery = query.toLowerCase()
    return allIcons.filter(
        (icon) =>
            icon.name.toLowerCase().includes(lowercaseQuery) ||
            icon.displayName.toLowerCase().includes(lowercaseQuery) ||
            icon.category.toLowerCase().includes(lowercaseQuery) ||
            icon.keywords.some((keyword) =>
                keyword.toLowerCase().includes(lowercaseQuery),
            ),
    )
}

export const getIconsByCategory = (category: string): IconMetadata[] => {
    return allIcons.filter((icon) => icon.category === category)
}

export const getAllCategories = (): string[] => {
    const categories = new Set(allIcons.map((icon) => icon.category))
    return Array.from(categories).sort()
}

export const getCategoryCount = (category: string): number => {
    return allIcons.filter((icon) => icon.category === category).length
}

// Memoized category data for performance (computed once, cached)
let _categoryCache: Record<string, IconMetadata[]> | null = null
export const getIconCategories = (): Record<string, IconMetadata[]> => {
    if (!_categoryCache) {
        _categoryCache = {}
        for (const icon of allIcons) {
            if (!_categoryCache[icon.category]) {
                _categoryCache[icon.category] = []
            }
            _categoryCache[icon.category].push(icon)
        }
        // Sort icons within each category
        for (const category in _categoryCache) {
            _categoryCache[category].sort((a, b) =>
                a.name.localeCompare(b.name),
            )
        }
    }
    return _categoryCache
}
